use std::collections::HashMap;
use std::net::SocketAddr;
use std::sync::{Arc, Mutex};
use std::time::{SystemTime, UNIX_EPOCH};

use anyhow::Result;
use axum::body::Body;
use axum::extract::State;
use axum::http::{header, HeaderMap, StatusCode};
use axum::response::Response;
use axum::routing::{get, post};
use axum::{Json, Router};
use genai::Client;
use serde::{Deserialize, Serialize};
use serde_json::{json, Value};

use crate::policy::RuntimePolicy;
use crate::rlm::{Rlm, RlmConfig};
use crate::store::ContextStore;
use crate::tools::ToolRegistry;

#[derive(Clone)]
pub struct OpenAiServer {
    state: Arc<OpenAiState>,
}

#[derive(Clone)]
struct OpenAiState {
    client: Client,
    model: String,
    sub_model: String,
    max_iterations: usize,
    max_depth: usize,
    store: ContextStore,
    verbose: bool,
    trace_sandbox: bool,
    default_runtime_policy: RuntimePolicy,
    tool_registry: Arc<Mutex<ToolRegistry>>,
}

#[derive(Debug, Deserialize)]
struct ChatCompletionsRequest {
    model: Option<String>,
    messages: Vec<OpenAiMessage>,
    #[serde(default)]
    stream: bool,
    #[serde(default)]
    metadata: Option<HashMap<String, Value>>,
    #[serde(default)]
    user: Option<String>,
}

#[derive(Debug, Deserialize)]
struct OpenAiMessage {
    role: String,
    #[serde(default)]
    content: Option<MessageContent>,
}

#[derive(Debug, Deserialize)]
#[serde(untagged)]
enum MessageContent {
    Text(String),
    Parts(Vec<ContentPart>),
}

#[derive(Debug, Deserialize)]
struct ContentPart {
    #[serde(default)]
    text: Option<String>,
}

#[derive(Debug, Deserialize)]
struct ResponsesRequest {
    model: Option<String>,
    input: ResponseInput,
    #[serde(default)]
    instructions: Option<String>,
    #[serde(default)]
    stream: bool,
    #[serde(default)]
    metadata: Option<HashMap<String, Value>>,
    #[serde(default)]
    user: Option<String>,
}

#[derive(Debug, Deserialize)]
#[serde(untagged)]
enum ResponseInput {
    Text(String),
    Messages(Vec<OpenAiMessage>),
}

#[derive(Debug, Serialize)]
struct ModelsResponse {
    object: &'static str,
    data: Vec<ModelInfo>,
}

#[derive(Debug, Serialize)]
struct ModelInfo {
    id: String,
    object: &'static str,
    created: u64,
    owned_by: &'static str,
}

impl OpenAiServer {
    #[allow(clippy::too_many_arguments)]
    pub fn new(
        client: Client,
        model: String,
        sub_model: String,
        max_iterations: usize,
        max_depth: usize,
        store: ContextStore,
        verbose: bool,
        trace_sandbox: bool,
        default_runtime_policy: RuntimePolicy,
    ) -> Self {
        Self {
            state: Arc::new(OpenAiState {
                client,
                model,
                sub_model,
                max_iterations,
                max_depth,
                store,
                verbose,
                trace_sandbox,
                default_runtime_policy,
                tool_registry: Arc::new(Mutex::new(ToolRegistry::new())),
            }),
        }
    }

    pub async fn serve(self, bind_addr: SocketAddr) -> Result<()> {
        let app = Router::new()
            .route("/v1/models", get(list_models))
            .route("/v1/chat/completions", post(chat_completions))
            .route("/v1/responses", post(responses))
            .with_state(self.state);
        let listener = tokio::net::TcpListener::bind(bind_addr).await?;
        axum::serve(listener, app).await?;
        Ok(())
    }
}

async fn list_models(State(state): State<Arc<OpenAiState>>) -> Response {
    let created = unix_timestamp();
    json_response(
        StatusCode::OK,
        &ModelsResponse {
            object: "list",
            data: vec![ModelInfo {
                id: state.model.clone(),
                object: "model",
                created,
                owned_by: "axon",
            }],
        },
    )
}

async fn chat_completions(
    State(state): State<Arc<OpenAiState>>,
    headers: HeaderMap,
    Json(req): Json<ChatCompletionsRequest>,
) -> Response {
    let Some(query) = latest_user_message(&req.messages) else {
        return error_response(
            StatusCode::BAD_REQUEST,
            "messages must include user content",
        );
    };
    let thread_id = thread_id(req.metadata.as_ref(), req.user.as_deref(), &headers);
    let request_context = render_messages(&req.messages);

    match run_rlm_query_blocking(
        &state,
        req.model.as_deref(),
        &thread_id,
        &query,
        &request_context,
    ) {
        Ok(answer) if req.stream => chat_stream_response(&state, req.model.as_deref(), &answer),
        Ok(answer) => chat_json_response(&state, req.model.as_deref(), &answer),
        Err(err) => error_response(StatusCode::INTERNAL_SERVER_ERROR, &err.to_string()),
    }
}

async fn responses(
    State(state): State<Arc<OpenAiState>>,
    headers: HeaderMap,
    Json(req): Json<ResponsesRequest>,
) -> Response {
    let (query, rendered_input) = match response_input_parts(&req.input) {
        Some(parts) => parts,
        None => return error_response(StatusCode::BAD_REQUEST, "input must include user content"),
    };
    let thread_id = thread_id(req.metadata.as_ref(), req.user.as_deref(), &headers);
    let request_context = if let Some(instructions) = req.instructions.as_deref() {
        format!("SYSTEM: {}\n{}", instructions, rendered_input)
    } else {
        rendered_input
    };

    match run_rlm_query_blocking(
        &state,
        req.model.as_deref(),
        &thread_id,
        &query,
        &request_context,
    ) {
        Ok(answer) if req.stream => {
            responses_stream_response(&state, req.model.as_deref(), &answer)
        }
        Ok(answer) => responses_json_response(&state, req.model.as_deref(), &answer),
        Err(err) => error_response(StatusCode::INTERNAL_SERVER_ERROR, &err.to_string()),
    }
}

fn run_rlm_query_blocking(
    state: &OpenAiState,
    model_override: Option<&str>,
    thread_id: &str,
    query: &str,
    request_context: &str,
) -> Result<String> {
    tokio::task::block_in_place(|| {
        let stored_context = state.store.read_context(thread_id);
        let context = if stored_context.trim().is_empty() {
            request_context.to_string()
        } else {
            format!("{stored_context}\n\n[CURRENT REQUEST]\n{request_context}")
        };
        let tool_registry = state
            .tool_registry
            .lock()
            .expect("tool registry lock")
            .clone();
        let rlm = Rlm::new(RlmConfig {
            client: state.client.clone(),
            model: model_override.unwrap_or(&state.model).to_string(),
            sub_model: state.sub_model.clone(),
            max_iterations: state.max_iterations,
            depth: 0,
            max_depth: state.max_depth,
            verbose: state.verbose,
            trace_sandbox: state.trace_sandbox,
            runtime_policy: state.default_runtime_policy.clone(),
            tool_registry,
        });
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .expect("OpenAI-compatible route runtime");
        let answer = rt.block_on(rlm.completion(query, &context))?;
        state.store.append_context(
            thread_id,
            &format!("\nUSER: {}\nASSISTANT: {}\n", query, answer),
        )?;
        Ok(answer)
    })
}

fn latest_user_message(messages: &[OpenAiMessage]) -> Option<String> {
    messages
        .iter()
        .rev()
        .find(|message| message.role == "user")
        .and_then(|message| message_text(message).filter(|text| !text.trim().is_empty()))
}

fn response_input_parts(input: &ResponseInput) -> Option<(String, String)> {
    match input {
        ResponseInput::Text(text) if !text.trim().is_empty() => {
            Some((text.clone(), format!("USER: {}", text)))
        }
        ResponseInput::Text(_) => None,
        ResponseInput::Messages(messages) => {
            let query = latest_user_message(messages)?;
            Some((query, render_messages(messages)))
        }
    }
}

fn render_messages(messages: &[OpenAiMessage]) -> String {
    messages
        .iter()
        .filter_map(|message| {
            let text = message_text(message)?;
            if text.trim().is_empty() {
                return None;
            }
            Some(format!("{}: {}", message.role.to_uppercase(), text))
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn message_text(message: &OpenAiMessage) -> Option<String> {
    match message.content.as_ref()? {
        MessageContent::Text(text) => Some(text.clone()),
        MessageContent::Parts(parts) => {
            let text = parts
                .iter()
                .filter_map(|part| part.text.as_deref())
                .collect::<Vec<_>>()
                .join("\n");
            Some(text)
        }
    }
}

fn thread_id(
    metadata: Option<&HashMap<String, Value>>,
    user: Option<&str>,
    headers: &HeaderMap,
) -> String {
    if let Some(value) = headers
        .get("x-axon-thread")
        .and_then(|value| value.to_str().ok())
        .filter(|value| !value.trim().is_empty())
    {
        return value.trim().to_string();
    }
    if let Some(value) = metadata
        .and_then(|metadata| metadata.get("thread_id"))
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
    {
        return value.trim().to_string();
    }
    user.filter(|value| !value.trim().is_empty())
        .unwrap_or("default")
        .trim()
        .to_string()
}

fn chat_json_response(state: &OpenAiState, request_model: Option<&str>, answer: &str) -> Response {
    let created = unix_timestamp();
    let model = request_model.unwrap_or(&state.model);
    json_response(
        StatusCode::OK,
        &json!({
            "id": response_id("chatcmpl"),
            "object": "chat.completion",
            "created": created,
            "model": model,
            "choices": [{
                "index": 0,
                "message": {
                    "role": "assistant",
                    "content": answer
                },
                "finish_reason": "stop"
            }]
        }),
    )
}

fn chat_stream_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("chatcmpl");
    let model = request_model.unwrap_or(&state.model);
    let first = json!({
        "id": id,
        "object": "chat.completion.chunk",
        "created": created,
        "model": model,
        "choices": [{
            "index": 0,
            "delta": {
                "role": "assistant",
                "content": answer
            },
            "finish_reason": null
        }]
    });
    let done = json!({
        "id": id,
        "object": "chat.completion.chunk",
        "created": created,
        "model": model,
        "choices": [{
            "index": 0,
            "delta": {},
            "finish_reason": "stop"
        }]
    });
    sse_response(vec![first, done])
}

fn responses_json_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("resp");
    let model = request_model.unwrap_or(&state.model);
    json_response(
        StatusCode::OK,
        &json!({
            "id": id,
            "object": "response",
            "created_at": created,
            "status": "completed",
            "model": model,
            "output": [{
                "id": response_id("msg"),
                "type": "message",
                "status": "completed",
                "role": "assistant",
                "content": [{
                    "type": "output_text",
                    "text": answer,
                    "annotations": []
                }]
            }],
            "output_text": answer
        }),
    )
}

fn responses_stream_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("resp");
    let model = request_model.unwrap_or(&state.model);
    sse_response(vec![
        json!({
            "type": "response.output_text.delta",
            "response_id": id,
            "delta": answer
        }),
        json!({
            "type": "response.completed",
            "response": {
                "id": id,
                "object": "response",
                "created_at": created,
                "status": "completed",
                "model": model,
                "output_text": answer
            }
        }),
    ])
}

fn sse_response(events: Vec<Value>) -> Response {
    let mut body = String::new();
    for event in events {
        body.push_str("data: ");
        body.push_str(&event.to_string());
        body.push_str("\n\n");
    }
    body.push_str("data: [DONE]\n\n");
    response_with_content_type(StatusCode::OK, "text/event-stream", body)
}

fn json_response<T: Serialize>(status: StatusCode, value: &T) -> Response {
    let body = serde_json::to_string(value).expect("JSON serialization should not fail");
    response_with_content_type(status, "application/json", body)
}

fn error_response(status: StatusCode, message: &str) -> Response {
    json_response(
        status,
        &json!({
            "error": {
                "message": message,
                "type": "server_error",
                "param": null,
                "code": null
            }
        }),
    )
}

fn response_with_content_type(
    status: StatusCode,
    content_type: &'static str,
    body: String,
) -> Response {
    Response::builder()
        .status(status)
        .header(header::CONTENT_TYPE, content_type)
        .body(Body::from(body))
        .expect("response builder should accept static headers")
}

fn response_id(prefix: &str) -> String {
    format!("{}-{}", prefix, unix_timestamp_nanos())
}

fn unix_timestamp() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

fn unix_timestamp_nanos() -> u128 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn text_message(role: &str, content: &str) -> OpenAiMessage {
        OpenAiMessage {
            role: role.to_string(),
            content: Some(MessageContent::Text(content.to_string())),
        }
    }

    #[test]
    fn latest_user_message_uses_last_user_message() {
        let messages = vec![
            text_message("user", "first"),
            text_message("assistant", "middle"),
            text_message("user", "second"),
        ];

        assert_eq!(latest_user_message(&messages), Some("second".to_string()));
    }

    #[test]
    fn thread_id_prefers_header_then_metadata_then_user() {
        let mut headers = HeaderMap::new();
        headers.insert("x-axon-thread", "header-thread".parse().unwrap());
        let mut metadata = HashMap::new();
        metadata.insert(
            "thread_id".to_string(),
            Value::String("meta-thread".to_string()),
        );

        assert_eq!(
            thread_id(Some(&metadata), Some("user-thread"), &headers),
            "header-thread"
        );

        let headers = HeaderMap::new();
        assert_eq!(
            thread_id(Some(&metadata), Some("user-thread"), &headers),
            "meta-thread"
        );

        assert_eq!(
            thread_id(None, Some("user-thread"), &headers),
            "user-thread"
        );
        assert_eq!(thread_id(None, None, &headers), "default");
    }

    #[test]
    fn render_messages_includes_roles() {
        let messages = vec![
            text_message("system", "be terse"),
            text_message("user", "hello"),
        ];

        assert_eq!(render_messages(&messages), "SYSTEM: be terse\nUSER: hello");
    }
}

use std::net::SocketAddr;
use std::path::PathBuf;

use anyhow::{bail, Result};
use clap::{Parser, Subcommand};
use genai::adapter::AdapterKind;
use genai::resolver::{AuthData, Endpoint, ServiceTargetResolver};
use genai::{Client, ModelIden, ServiceTarget};

use axon::mcp::McpServer;
use axon::openai::OpenAiServer;
use axon::policy::{DepthEnforcementMode, PolicyCatalog, RuntimePolicy};
use axon::rlm::{Rlm, RlmConfig};
use axon::store::ContextStore;
use axon::tools::ToolRegistry;

#[derive(Debug, Parser)]
#[command(
    name = "axon",
    about = "Recursive Language Model engine - one context, run everywhere"
)]
struct Cli {
    /// Root LLM model
    #[arg(long, default_value = "hf:MiniMaxAI/MiniMax-M2.5")]
    model: String,

    /// Sub-RLM model (used for recursive calls)
    #[arg(long, default_value = "hf:MiniMaxAI/MiniMax-M2.5")]
    sub_model: String,

    /// Custom provider base URL (e.g. for Synthetic/MiniMax)
    #[arg(
        long,
        env = "AXON_BASE_URL",
        default_value = "https://api.synthetic.new/openai/v1/"
    )]
    base_url: Option<String>,

    /// API key (overrides env var auto-detection)
    #[arg(long, env = "AXON_API_KEY", hide_env_values = true)]
    api_key: Option<String>,

    /// Max iterations per RLM level
    #[arg(long, default_value_t = 10)]
    max_iterations: usize,

    /// Max recursion depth for sub-RLM calls (0 = direct LLM, no sandbox)
    #[arg(long, default_value_t = 1)]
    max_depth: usize,

    /// Data directory for persistent context
    #[arg(long, default_value = "data")]
    data_dir: PathBuf,

    /// Verbose logging to stderr
    #[arg(short, long)]
    verbose: bool,

    /// Trace sandbox execution steps (code blocks, external calls, vars) to stderr
    #[arg(long)]
    trace_sandbox: bool,

    /// Prompt policy profile name
    #[arg(long, default_value = "baseline")]
    policy_profile: String,

    /// Prompt policy config path
    #[arg(long, default_value = "config/prompt_policies.json")]
    policy_config: PathBuf,

    /// Prepend active policy text into context as an option
    #[arg(long)]
    inject_policy_into_context: bool,

    /// Depth-enforcement mode
    #[arg(long, value_enum, default_value_t = DepthEnforcementMode::Off)]
    depth_enforcement: DepthEnforcementMode,

    /// Strict mode minimum depth threshold (absolute depth)
    #[arg(long)]
    require_min_depth: Option<usize>,

    /// Strict mode minimum recursive llm_query call count
    #[arg(long)]
    require_min_recursive_calls: Option<usize>,

    #[command(subcommand)]
    command: Commands,
}

#[derive(Debug, Subcommand)]
enum Commands {
    /// One-shot query against a context file
    Query {
        /// The question to ask
        query: String,

        /// Path to context file
        #[arg(short, long)]
        context: Option<PathBuf>,

        /// Thread ID (reads from data dir)
        #[arg(short, long)]
        thread: Option<String>,
    },

    /// Interactive chat with persistent thread context
    Chat {
        /// Thread identifier (context accumulates per thread)
        #[arg(short, long, default_value = "default")]
        thread: String,
    },

    /// Append text to a thread's context store
    Store {
        /// File to read (or - for stdin)
        file: String,

        /// Thread to store under
        #[arg(short, long, default_value = "transcripts")]
        thread: String,
    },

    /// Run as an MCP server over stdio or streamable HTTP
    Serve {
        /// MCP transport to serve
        #[arg(long, value_enum, default_value_t = McpTransport::Stdio)]
        transport: McpTransport,

        /// Address to bind for HTTP transport
        #[arg(long, default_value = "127.0.0.1:3000")]
        bind: SocketAddr,

        /// Route path for HTTP transport
        #[arg(long, default_value = "/mcp")]
        path: String,
    },

    /// Run an OpenAI-compatible HTTP server for agent base_url integrations
    #[command(name = "serve-openai", alias = "serve-open-ai")]
    ServeOpenAi {
        /// Address to bind for the OpenAI-compatible HTTP server
        #[arg(long, default_value = "127.0.0.1:3000")]
        bind: SocketAddr,
    },
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, clap::ValueEnum)]
enum McpTransport {
    Stdio,
    StreamableHttp,
}

fn build_client(base_url: Option<&str>, api_key: Option<&str>) -> Client {
    let mut builder = Client::builder();

    if let Some(url) = base_url {
        let url = url.to_string();
        let key = api_key.map(|k| k.to_string());

        let resolver = ServiceTargetResolver::from_resolver_fn(move |target: ServiceTarget| {
            Ok(ServiceTarget {
                endpoint: Endpoint::from_owned(url.clone()),
                auth: key
                    .as_ref()
                    .map(|k| AuthData::from_single(k.clone()))
                    .unwrap_or(target.auth),
                model: ModelIden::new(AdapterKind::OpenAI, target.model.model_name),
            })
        });
        builder = builder.with_service_target_resolver(resolver);
    } else if let Some(key) = api_key {
        let key = key.to_string();
        let resolver = ServiceTargetResolver::from_resolver_fn(move |mut target: ServiceTarget| {
            target.auth = AuthData::from_single(key.clone());
            Ok(target)
        });
        builder = builder.with_service_target_resolver(resolver);
    }

    builder.build()
}

#[tokio::main]
async fn main() -> Result<()> {
    let cli = Cli::parse();

    let client = build_client(cli.base_url.as_deref(), cli.api_key.as_deref());
    let store = ContextStore::new(&cli.data_dir);
    let policy_catalog = PolicyCatalog::load(&cli.policy_config);
    let default_runtime_policy = policy_catalog.build_runtime_policy(
        Some(&cli.policy_profile),
        Some(cli.inject_policy_into_context),
        Some(cli.depth_enforcement),
        cli.require_min_depth,
        cli.require_min_recursive_calls,
    );

    match cli.command {
        Commands::Query {
            ref query,
            ref context,
            ref thread,
        } => {
            let ctx = match (context, thread) {
                (Some(path), _) => std::fs::read_to_string(path)?,
                (None, Some(tid)) => store.read_context(tid),
                (None, None) => bail!("Provide --context <file> or --thread <id>"),
            };

            let rlm = make_rlm(&client, &cli, 0, default_runtime_policy.clone());
            let answer = rlm.completion(query, &ctx).await?;
            println!("{}", answer);
        }

        Commands::Chat { ref thread } => {
            eprintln!("Axon RLM - thread '{}'. Type 'exit' to quit.", thread);
            let stdin = std::io::stdin();
            loop {
                eprint!("You: ");
                let mut line = String::new();
                if stdin.read_line(&mut line)? == 0 {
                    break;
                }
                let query = line.trim();
                if query.is_empty() {
                    continue;
                }
                if matches!(query, "exit" | "quit" | ":q") {
                    eprintln!("Goodbye!");
                    break;
                }

                let ctx = store.read_context(thread);
                let rlm = make_rlm(&client, &cli, 0, default_runtime_policy.clone());

                eprintln!("Thinking...");
                match rlm.completion(query, &ctx).await {
                    Ok(answer) => {
                        println!("Assistant: {}", answer);
                        let _ = store.append_context(
                            thread,
                            &format!("\nUSER: {}\nASSISTANT: {}\n", query, answer),
                        );
                    }
                    Err(e) => eprintln!("Error: {}", e),
                }
            }
        }

        Commands::Store {
            ref file,
            ref thread,
        } => {
            let text = if file == "-" {
                let mut buf = String::new();
                std::io::Read::read_to_string(&mut std::io::stdin(), &mut buf)?;
                buf
            } else {
                std::fs::read_to_string(file)?
            };

            if text.trim().is_empty() {
                bail!("No content to store.");
            }

            store.append_context(thread, &text)?;
            eprintln!("Appended {} chars to thread '{}'.", text.len(), thread);
        }

        Commands::Serve {
            transport,
            ref path,
            bind,
        } => {
            let server = McpServer::new(
                client,
                cli.model.clone(),
                cli.sub_model.clone(),
                cli.max_iterations,
                cli.max_depth,
                store,
                cli.verbose,
                cli.trace_sandbox,
                policy_catalog,
                default_runtime_policy,
            );
            match transport {
                McpTransport::Stdio => server.serve_stdio().await?,
                McpTransport::StreamableHttp => server.serve_http(bind, path).await?,
            }
        }

        Commands::ServeOpenAi { bind } => {
            let server = OpenAiServer::new(
                client,
                cli.model.clone(),
                cli.sub_model.clone(),
                cli.max_iterations,
                cli.max_depth,
                store,
                cli.verbose,
                cli.trace_sandbox,
                default_runtime_policy,
            );
            eprintln!("Axon OpenAI-compatible server listening on http://{bind}/v1");
            server.serve(bind).await?;
        }
    }

    Ok(())
}

fn make_rlm(client: &Client, cli: &Cli, depth: usize, runtime_policy: RuntimePolicy) -> Rlm {
    Rlm::new(RlmConfig {
        client: client.clone(),
        model: cli.model.clone(),
        sub_model: cli.sub_model.clone(),
        max_iterations: cli.max_iterations,
        depth,
        max_depth: cli.max_depth,
        verbose: cli.verbose,
        trace_sandbox: cli.trace_sandbox,
        runtime_policy,
        tool_registry: ToolRegistry::new(),
    })
}

