        let resolved_model = args_no_override.model.unwrap_or_else(|| server.model.clone());
        let resolved_sub = args_no_override.sub_model.unwrap_or_else(|| server.sub_model.clone());
        assert_eq!(resolved_model, "default-model");
        assert_eq!(resolved_sub, "default-sub-model");

        let args_with_override = ChatRlmQueryArgs {
