        }
    }

    pub async fn serve_stdio(self) -> Result<()> {
        let server = self.serve(stdio()).await?;
        server.waiting().await?;
        Ok(())
    }

    pub async fn serve_http(self, bind_addr: SocketAddr, path: &str) -> Result<()> {
        let normalized_path = normalize_http_path(path);
        let mut config = StreamableHttpServerConfig::default();
        config.allowed_hosts = allowed_hosts_for(bind_addr);

        let factory = {
            let server = self.clone();
            move || Ok(server.clone())
        };
        let service =
            StreamableHttpService::new(factory, Arc::new(LocalSessionManager::default()), config);
        let app = Router::new().route_service(&normalized_path, service);
        let listener = tokio::net::TcpListener::bind(bind_addr).await?;

        axum::serve(listener, app).await?;
        Ok(())
    }

    fn run_chat_rlm_query(&self, args: ChatRlmQueryArgs) -> CallToolResult {
        let query = args.query.trim();
        let thread_id = args.thread_id.trim();

        if query.is_empty() {
            return tool_error("query cannot be empty");
        }
        if thread_id.is_empty() {
            return tool_error("thread_id cannot be empty");
        }

        let context = self.store.read_context(thread_id);
        let mut runtime_policy = if let Some(profile) = args.policy_profile.as_deref() {
            self.policy_catalog
                .build_runtime_policy(Some(profile), None, None, None, None)
        } else {
            self.default_runtime_policy.clone()
        };
        if let Some(v) = args.inject_policy_into_context {
            runtime_policy.inject_policy_into_context = v;
        }
        if let Some(v) = parse_depth_mode(args.depth_enforcement.as_deref()) {
            runtime_policy.depth_enforcement = v;
        }
        if let Some(v) = args.require_min_depth {
            runtime_policy.require_min_depth = Some(v);
        }
        if let Some(v) = args.require_min_recursive_calls {
            runtime_policy.require_min_recursive_calls = Some(v);
        }

        tokio::task::block_in_place(|| {
            let model = args.model.unwrap_or_else(|| self.model.clone());
            let sub_model = args.sub_model.unwrap_or_else(|| self.sub_model.clone());
            let tool_registry = self
                .tool_registry
                .lock()
                .expect("tool registry lock")
                .clone();
            let rlm = Rlm::new(RlmConfig {
                client: self.client.clone(),
                model,
                sub_model,
                max_iterations: self.max_iterations,
                depth: 0,
                max_depth: self.max_depth,
                verbose: self.verbose,
                trace_sandbox: self.trace_sandbox,
                runtime_policy,
                tool_registry,
            });
            let rt = tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build()
                .expect("tool runtime");

            match rt.block_on(rlm.completion(query, &context)) {
                Ok(answer) => {
                    let _ = self.store.append_context(
                        thread_id,
                        &format!("\nUSER: {}\nASSISTANT: {}\n", query, answer),
                    );
                    tool_result(&answer)
                }
                Err(e) => tool_error(&format!("RLM error: {}", e)),
            }
        })
    }

    fn run_upload_context(&self, args: UploadContextArgs) -> CallToolResult {
        let transcript = args.transcript.trim();
        let session_id = args.session_id.trim();
        let thread_id = args.thread_id.as_deref().unwrap_or("transcripts").trim();

        if transcript.is_empty() {
            return tool_error("transcript cannot be empty");
        }
        if session_id.is_empty() {
            return tool_error("session_id cannot be empty");
        }
        if thread_id.is_empty() {
            return tool_error("thread_id cannot be empty");
        }

        let text = format!("\n[SESSION {}]\n{}\n", session_id, transcript);
        match self.store.append_context(thread_id, &text) {
            Ok(()) => tool_result(&format!(
                "Uploaded session {} to thread '{}'.",
                session_id, thread_id
            )),
            Err(e) => tool_error(&format!("Store error: {}", e)),
        }
    }

    fn run_configure_tools(&self, args: ConfigureToolsArgs) -> CallToolResult {
        if args.tools.is_empty() {
            return tool_error("tools list cannot be empty");
        }
        let mut registry = self.tool_registry.lock().expect("tool registry lock");
        let mut registered = Vec::new();
        for spec in args.tools {
            let name = spec.name.clone();
            registry.register(spec);
            registered.push(name);
        }
        tool_result(&format!("Registered tools: {}", registered.join(", ")))
    }
}

