use std::collections::HashMap;
use std::net::SocketAddr;
use std::sync::{Arc, Mutex};
use std::time::{SystemTime, UNIX_EPOCH};

use anyhow::Result;
use axum::body::Body;
use axum::extract::State;
use axum::http::{header, HeaderMap, StatusCode};
use axum::response::Response;
use axum::routing::{get, post};
use axum::{Json, Router};
use genai::Client;
use serde::{Deserialize, Serialize};
use serde_json::{json, Value};

use crate::policy::RuntimePolicy;
use crate::service::{QueryRequest, RlmService};
use crate::store::ContextStore;

#[derive(Clone)]
pub struct OpenAiServer {
    service: RlmService,
}

#[derive(Clone)]
struct OpenAiState {
    service: RlmService,
}

#[derive(Debug, Deserialize)]
struct ChatCompletionsRequest {
    model: Option<String>,
    messages: Vec<OpenAiMessage>,
    #[serde(default)]
    stream: bool,
    #[serde(default)]
    metadata: Option<HashMap<String, Value>>,
    #[serde(default)]
    user: Option<String>,
}

#[derive(Debug, Deserialize)]
struct OpenAiMessage {
    role: String,
    #[serde(default)]
    content: Option<MessageContent>,
}

#[derive(Debug, Deserialize)]
#[serde(untagged)]
enum MessageContent {
    Text(String),
    Parts(Vec<ContentPart>),
}

#[derive(Debug, Deserialize)]
struct ContentPart {
    #[serde(default)]
    text: Option<String>,
}

#[derive(Debug, Deserialize)]
struct ResponsesRequest {
    model: Option<String>,
    input: ResponseInput,
    #[serde(default)]
    instructions: Option<String>,
    #[serde(default)]
    stream: bool,
    #[serde(default)]
    metadata: Option<HashMap<String, Value>>,
    #[serde(default)]
    user: Option<String>,
}

#[derive(Debug, Deserialize)]
#[serde(untagged)]
enum ResponseInput {
    Text(String),
    Messages(Vec<OpenAiMessage>),
}

#[derive(Debug, Serialize)]
struct ModelsResponse {
    object: &'static str,
    data: Vec<ModelInfo>,
}

#[derive(Debug, Serialize)]
struct ModelInfo {
    id: String,
    object: &'static str,
    created: u64,
    owned_by: &'static str,
}

impl OpenAiServer {
    #[allow(clippy::too_many_arguments)]
    pub fn new(
        client: Client,
        model: String,
        sub_model: String,
        max_iterations: usize,
        max_depth: usize,
        store: ContextStore,
        verbose: bool,
        trace_sandbox: bool,
        policy_catalog: crate::policy::PolicyCatalog,
        default_runtime_policy: RuntimePolicy,
    ) -> Self {
        Self {
            service: RlmService::new(
                client,
                model,
                sub_model,
                max_iterations,
                max_depth,
                store,
                verbose,
                trace_sandbox,
                policy_catalog,
                default_runtime_policy,
            ),
        }
    }

    pub async fn serve(self, bind_addr: SocketAddr) -> Result<()> {
        let state = Arc::new(OpenAiState {
            service: self.service,
        });
        let app = Router::new()
            .route("/v1/models", get(list_models))
            .route("/v1/chat/completions", post(chat_completions))
            .route("/v1/responses", post(responses))
            .with_state(state);
        let listener = tokio::net::TcpListener::bind(bind_addr).await?;
        axum::serve(listener, app).await?;
        Ok(())
    }
}

async fn list_models(State(state): State<Arc<OpenAiState>>) -> Response {
    let created = unix_timestamp();
    json_response(
        StatusCode::OK,
        &ModelsResponse {
            object: "list",
            data: vec![ModelInfo {
                id: state.service.model.clone(),
                object: "model",
                created,
                owned_by: "axon",
            }],
        },
    )
}

async fn chat_completions(
    State(state): State<Arc<OpenAiState>>,
    headers: HeaderMap,
    Json(req): Json<ChatCompletionsRequest>,
) -> Response {
    let Some(query) = latest_user_message(&req.messages) else {
        return error_response(
            StatusCode::BAD_REQUEST,
            "messages must include user content",
        );
    };
    let thread_id = thread_id(req.metadata.as_ref(), req.user.as_deref(), &headers);
    let request_context = render_messages(&req.messages);

    match run_rlm_query_blocking(
        &state,
        req.model.as_deref(),
        &thread_id,
        &query,
        &request_context,
    ) {
        Ok(answer) if req.stream => chat_stream_response(&state, req.model.as_deref(), &answer),
        Ok(answer) => chat_json_response(&state, req.model.as_deref(), &answer),
        Err(err) => error_response(StatusCode::INTERNAL_SERVER_ERROR, &err.to_string()),
    }
}

async fn responses(
    State(state): State<Arc<OpenAiState>>,
    headers: HeaderMap,
    Json(req): Json<ResponsesRequest>,
) -> Response {
    let (query, rendered_input) = match response_input_parts(&req.input) {
        Some(parts) => parts,
        None => return error_response(StatusCode::BAD_REQUEST, "input must include user content"),
    };
    let thread_id = thread_id(req.metadata.as_ref(), req.user.as_deref(), &headers);
    let request_context = if let Some(instructions) = req.instructions.as_deref() {
        format!("SYSTEM: {}\n{}", instructions, rendered_input)
    } else {
        rendered_input
    };

    match run_rlm_query_blocking(
        &state,
        req.model.as_deref(),
        &thread_id,
        &query,
        &request_context,
    ) {
        Ok(answer) if req.stream => {
            responses_stream_response(&state, req.model.as_deref(), &answer)
        }
        Ok(answer) => responses_json_response(&state, req.model.as_deref(), &answer),
        Err(err) => error_response(StatusCode::INTERNAL_SERVER_ERROR, &err.to_string()),
    }
}

fn run_rlm_query_blocking(
    state: &OpenAiState,
    model_override: Option<&str>,
    thread_id: &str,
    query: &str,
    request_context: &str,
) -> Result<String> {
    tokio::task::block_in_place(|| {
        let stored_context = state.store.read_context(thread_id);
        let context = if stored_context.trim().is_empty() {
            request_context.to_string()
        } else {
            format!("{stored_context}\n\n[CURRENT REQUEST]\n{request_context}")
        };
        let tool_registry = state
            .tool_registry
            .lock()
            .expect("tool registry lock")
            .clone();
        let rlm = Rlm::new(RlmConfig {
            client: state.client.clone(),
            model: model_override.unwrap_or(&state.model).to_string(),
            sub_model: state.sub_model.clone(),
            max_iterations: state.max_iterations,
            depth: 0,
            max_depth: state.max_depth,
            verbose: state.verbose,
            trace_sandbox: state.trace_sandbox,
            runtime_policy: state.default_runtime_policy.clone(),
            tool_registry,
        });
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .expect("OpenAI-compatible route runtime");
        let answer = rt.block_on(rlm.completion(query, &context))?;
        state.store.append_context(
            thread_id,
            &format!("\nUSER: {}\nASSISTANT: {}\n", query, answer),
        )?;
        Ok(answer)
    })
}

fn latest_user_message(messages: &[OpenAiMessage]) -> Option<String> {
    messages
        .iter()
        .rev()
        .find(|message| message.role == "user")
        .and_then(|message| message_text(message).filter(|text| !text.trim().is_empty()))
}

fn response_input_parts(input: &ResponseInput) -> Option<(String, String)> {
    match input {
        ResponseInput::Text(text) if !text.trim().is_empty() => {
            Some((text.clone(), format!("USER: {}", text)))
        }
        ResponseInput::Text(_) => None,
        ResponseInput::Messages(messages) => {
            let query = latest_user_message(messages)?;
            Some((query, render_messages(messages)))
        }
    }
}

fn render_messages(messages: &[OpenAiMessage]) -> String {
    messages
        .iter()
        .filter_map(|message| {
            let text = message_text(message)?;
            if text.trim().is_empty() {
                return None;
            }
            Some(format!("{}: {}", message.role.to_uppercase(), text))
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn message_text(message: &OpenAiMessage) -> Option<String> {
    match message.content.as_ref()? {
        MessageContent::Text(text) => Some(text.clone()),
        MessageContent::Parts(parts) => {
            let text = parts
                .iter()
                .filter_map(|part| part.text.as_deref())
                .collect::<Vec<_>>()
                .join("\n");
            Some(text)
        }
    }
}

fn thread_id(
    metadata: Option<&HashMap<String, Value>>,
    user: Option<&str>,
    headers: &HeaderMap,
) -> String {
    if let Some(value) = headers
        .get("x-axon-thread")
        .and_then(|value| value.to_str().ok())
        .filter(|value| !value.trim().is_empty())
    {
        return value.trim().to_string();
    }
    if let Some(value) = metadata
        .and_then(|metadata| metadata.get("thread_id"))
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
    {
        return value.trim().to_string();
    }
    user.filter(|value| !value.trim().is_empty())
        .unwrap_or("default")
        .trim()
        .to_string()
}

fn chat_json_response(state: &OpenAiState, request_model: Option<&str>, answer: &str) -> Response {
    let created = unix_timestamp();
    let model = request_model.unwrap_or(&state.model);
    json_response(
        StatusCode::OK,
        &json!({
            "id": response_id("chatcmpl"),
            "object": "chat.completion",
            "created": created,
            "model": model,
            "choices": [{
                "index": 0,
                "message": {
                    "role": "assistant",
                    "content": answer
                },
                "finish_reason": "stop"
            }]
        }),
    )
}

fn chat_stream_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("chatcmpl");
    let model = request_model.unwrap_or(&state.model);
    let first = json!({
        "id": id,
        "object": "chat.completion.chunk",
        "created": created,
        "model": model,
        "choices": [{
            "index": 0,
            "delta": {
                "role": "assistant",
                "content": answer
            },
            "finish_reason": null
        }]
    });
    let done = json!({
        "id": id,
        "object": "chat.completion.chunk",
        "created": created,
        "model": model,
        "choices": [{
            "index": 0,
            "delta": {},
            "finish_reason": "stop"
        }]
    });
    sse_response(vec![first, done])
}

fn responses_json_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("resp");
    let model = request_model.unwrap_or(&state.model);
    json_response(
        StatusCode::OK,
        &json!({
            "id": id,
            "object": "response",
            "created_at": created,
            "status": "completed",
            "model": model,
            "output": [{
                "id": response_id("msg"),
                "type": "message",
                "status": "completed",
                "role": "assistant",
                "content": [{
                    "type": "output_text",
                    "text": answer,
                    "annotations": []
                }]
            }],
            "output_text": answer
        }),
    )
}

fn responses_stream_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("resp");
    let model = request_model.unwrap_or(&state.model);
    sse_response(vec![
        json!({
            "type": "response.output_text.delta",
