    } else {
        rendered_input
    };

    match run_rlm_query(
        &state,
        req.model.as_deref(),
        &thread_id,
        &query,
        &request_context,
    )
    .await
    {
        Ok(answer) if req.stream => {
            responses_stream_response(&state, req.model.as_deref(), &answer)
        }
        Ok(answer) => responses_json_response(&state, req.model.as_deref(), &answer),
        Err(err) => error_response(StatusCode::INTERNAL_SERVER_ERROR, &err.to_string()),
    }
}

fn run_rlm_query_blocking(
    state: &OpenAiState,
    model_override: Option<&str>,
    thread_id: &str,
    query: &str,
    request_context: &str,
) -> Result<String> {
    tokio::task::block_in_place(|| {
        let stored_context = state.store.read_context(thread_id);
        let context = if stored_context.trim().is_empty() {
            request_context.to_string()
        } else {
            format!("{stored_context}\n\n[CURRENT REQUEST]\n{request_context}")
        };
        let tool_registry = state
            .tool_registry
            .lock()
            .expect("tool registry lock")
            .clone();
        let rlm = Rlm::new(RlmConfig {
            client: state.client.clone(),
            model: model_override.unwrap_or(&state.model).to_string(),
            sub_model: state.sub_model.clone(),
            max_iterations: state.max_iterations,
            depth: 0,
            max_depth: state.max_depth,
            verbose: state.verbose,
            trace_sandbox: state.trace_sandbox,
            runtime_policy: state.default_runtime_policy.clone(),
            tool_registry,
        });
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .expect("OpenAI-compatible route runtime");
        let answer = rt.block_on(rlm.completion(query, &context))?;
        state.store.append_context(
            thread_id,
            &format!("\nUSER: {}\nASSISTANT: {}\n", query, answer),
        )?;
        Ok(answer)
    })
}

fn latest_user_message(messages: &[OpenAiMessage]) -> Option<String> {
    messages
        .iter()
        .rev()
        .find(|message| message.role == "user")
        .and_then(|message| message_text(message).filter(|text| !text.trim().is_empty()))
}

fn response_input_parts(input: &ResponseInput) -> Option<(String, String)> {
    match input {
        ResponseInput::Text(text) if !text.trim().is_empty() => {
            Some((text.clone(), format!("USER: {}", text)))
        }
        ResponseInput::Text(_) => None,
        ResponseInput::Messages(messages) => {
            let query = latest_user_message(messages)?;
            Some((query, render_messages(messages)))
        }
    }
}

fn render_messages(messages: &[OpenAiMessage]) -> String {
    messages
        .iter()
        .filter_map(|message| {
            let text = message_text(message)?;
            if text.trim().is_empty() {
                return None;
            }
            Some(format!("{}: {}", message.role.to_uppercase(), text))
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn message_text(message: &OpenAiMessage) -> Option<String> {
    match message.content.as_ref()? {
        MessageContent::Text(text) => Some(text.clone()),
        MessageContent::Parts(parts) => {
            let text = parts
                .iter()
                .filter_map(|part| part.text.as_deref())
                .collect::<Vec<_>>()
                .join("\n");
            Some(text)
        }
    }
}

fn thread_id(
    metadata: Option<&HashMap<String, Value>>,
    user: Option<&str>,
    headers: &HeaderMap,
) -> String {
    if let Some(value) = headers
        .get("x-axon-thread")
        .and_then(|value| value.to_str().ok())
        .filter(|value| !value.trim().is_empty())
    {
        return value.trim().to_string();
    }
    if let Some(value) = metadata
        .and_then(|metadata| metadata.get("thread_id"))
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
    {
        return value.trim().to_string();
    }
    user.filter(|value| !value.trim().is_empty())
        .unwrap_or("default")
        .trim()
        .to_string()
}

fn chat_json_response(state: &OpenAiState, request_model: Option<&str>, answer: &str) -> Response {
    let created = unix_timestamp();
    let model = request_model.unwrap_or(&state.model);
    json_response(
        StatusCode::OK,
        &json!({
            "id": response_id("chatcmpl"),
            "object": "chat.completion",
            "created": created,
            "model": model,
            "choices": [{
                "index": 0,
                "message": {
                    "role": "assistant",
                    "content": answer
                },
                "finish_reason": "stop"
            }]
        }),
    )
}

fn chat_stream_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("chatcmpl");
    let model = request_model.unwrap_or(&state.model);
    let first = json!({
        "id": id,
        "object": "chat.completion.chunk",
        "created": created,
        "model": model,
        "choices": [{
            "index": 0,
            "delta": {
                "role": "assistant",
                "content": answer
            },
            "finish_reason": null
        }]
    });
    let done = json!({
        "id": id,
        "object": "chat.completion.chunk",
        "created": created,
        "model": model,
        "choices": [{
            "index": 0,
            "delta": {},
            "finish_reason": "stop"
        }]
    });
    sse_response(vec![first, done])
}

fn responses_json_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("resp");
    let model = request_model.unwrap_or(&state.model);
    json_response(
        StatusCode::OK,
        &json!({
            "id": id,
            "object": "response",
            "created_at": created,
            "status": "completed",
            "model": model,
            "output": [{
                "id": response_id("msg"),
                "type": "message",
                "status": "completed",
                "role": "assistant",
                "content": [{
                    "type": "output_text",
                    "text": answer,
                    "annotations": []
                }]
            }],
            "output_text": answer
        }),
    )
}

fn responses_stream_response(
    state: &OpenAiState,
    request_model: Option<&str>,
    answer: &str,
) -> Response {
    let created = unix_timestamp();
    let id = response_id("resp");
    let model = request_model.unwrap_or(&state.model);
    sse_response(vec![
        json!({
            "type": "response.output_text.delta",
            "response_id": id,
            "delta": answer
        }),
        json!({
            "type": "response.completed",
            "response": {
                "id": id,
                "object": "response",
                "created_at": created,
                "status": "completed",
                "model": model,
                "output_text": answer
            }
        }),
    ])
}

fn sse_response(events: Vec<Value>) -> Response {
    let mut body = String::new();
    for event in events {
        body.push_str("data: ");
        body.push_str(&event.to_string());
        body.push_str("\n\n");
    }
    body.push_str("data: [DONE]\n\n");
    response_with_content_type(StatusCode::OK, "text/event-stream", body)
}

fn json_response<T: Serialize>(status: StatusCode, value: &T) -> Response {
    let body = serde_json::to_string(value).expect("JSON serialization should not fail");
    response_with_content_type(status, "application/json", body)
}

fn error_response(status: StatusCode, message: &str) -> Response {
    json_response(
        status,
        &json!({
            "error": {
                "message": message,
                "type": "server_error",
                "param": null,
                "code": null
            }
        }),
    )
}

fn response_with_content_type(
    status: StatusCode,
    content_type: &'static str,
    body: String,
) -> Response {
    Response::builder()
        .status(status)
        .header(header::CONTENT_TYPE, content_type)
        .body(Body::from(body))
        .expect("response builder should accept static headers")
}

fn response_id(prefix: &str) -> String {
    format!("{}-{}", prefix, unix_timestamp_nanos())
}

fn unix_timestamp() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

fn unix_timestamp_nanos() -> u128 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn text_message(role: &str, content: &str) -> OpenAiMessage {
        OpenAiMessage {
            role: role.to_string(),
            content: Some(MessageContent::Text(content.to_string())),
        }
    }

    #[test]
    fn latest_user_message_uses_last_user_message() {
        let messages = vec![
            text_message("user", "first"),
            text_message("assistant", "middle"),
            text_message("user", "second"),
        ];

        assert_eq!(latest_user_message(&messages), Some("second".to_string()));
    }

    #[test]
    fn thread_id_prefers_header_then_metadata_then_user() {
        let mut headers = HeaderMap::new();
        headers.insert("x-axon-thread", "header-thread".parse().unwrap());
        let mut metadata = HashMap::new();
        metadata.insert(
            "thread_id".to_string(),
            Value::String("meta-thread".to_string()),
        );

        assert_eq!(
            thread_id(Some(&metadata), Some("user-thread"), &headers),
            "header-thread"
        );

        let headers = HeaderMap::new();
        assert_eq!(
            thread_id(Some(&metadata), Some("user-thread"), &headers),
            "meta-thread"
        );

        assert_eq!(
            thread_id(None, Some("user-thread"), &headers),
            "user-thread"
        );
        assert_eq!(thread_id(None, None, &headers), "default");
    }

    #[test]
    fn render_messages_includes_roles() {
        let messages = vec![
            text_message("system", "be terse"),
            text_message("user", "hello"),
        ];

        assert_eq!(render_messages(&messages), "SYSTEM: be terse\nUSER: hello");
    }
}

