    #[test]
    fn render_messages_includes_roles() {
        let messages = vec![
            text_message("system", "be terse"),
            text_message("user", "hello"),
        ];

        assert_eq!(render_messages(&messages), "SYSTEM: be terse\nUSER: hello");
    }
}

