        let reg = server.service.tool_registry.lock().unwrap();
        assert_eq!(reg.tool_names(), vec!["FETCH", "SEARCH"]);
    }

    #[test]
    fn test_configure_tools_empty_returns_error() {
        let server = make_test_mcp_server();
        let args = ConfigureToolsArgs { tools: vec![] };
        let result = server.run_configure_tools(args);
        assert_eq!(result.is_error, Some(true));
