    fn exec_block(
        rt: &tokio::runtime::Runtime,
        rlm: &Rlm,
        sandbox: &mut Sandbox,
        runtime: &mut RuntimeState,
        code: &str,
    ) {
        let mut telemetry = DepthTelemetry::new(0);
